code = """import json, pandas as pd
cases = pd.DataFrame(var_call_WNcE0V7n6Qhh6s6htRnkaK6u)
accts = pd.DataFrame(var_call_gu2tAVZlfFbdN3JeRUYZlAxW)

# clean ids
cases['account_clean'] = cases['accountid'].astype(str).str.replace('#','', regex=False).str.strip()
accts['account_clean'] = accts['Id_clean'].astype(str).str.replace('#','', regex=False).str.strip()

# numeric
cases['avg_closure_days'] = pd.to_numeric(cases['avg_closure_days'], errors='coerce')
cases['case_count'] = pd.to_numeric(cases['case_count'], errors='coerce')

m = cases.merge(accts[['account_clean','ShippingState']], on='account_clean', how='left')
# drop missing state
m = m.dropna(subset=['ShippingState'])

# weighted avg by case_count across accounts
state = m.groupby('ShippingState', as_index=False).apply(
    lambda g: pd.Series({
        'weighted_avg_days': (g['avg_closure_days']*g['case_count']).sum()/g['case_count'].sum(),
        'cases': g['case_count'].sum()
    })
).reset_index(drop=True)

best = state.sort_values(['weighted_avg_days','cases'], ascending=[True, False]).head(1)
ans = best['ShippingState'].iloc[0] if len(best) else None
print('__RESULT__:')
print(json.dumps(ans))"""

